// string-utils.js -- библиотека без типов
function capitalize(str) {
  return str.charAt(0).toUpperCase() + str.slice(1);
}

function truncate(str, maxLength, suffix) {
  if (str.length <= maxLength) return str;
  return str.slice(0, maxLength) + (suffix || '...');
}

function repeat(str, times) {
  return str.repeat(times);
}

module.exports = { capitalize, truncate, repeat };

// Анализ:
// - module.exports = { ... } → CommonJS-модуль
// - Нет глобальных переменных
// - Нет UMD-обёртки
//
// Вывод: это модульная библиотека
// Шаблон: module-function / module с именованными экспортами
//
// Использование:
// const { capitalize, truncate } = require('string-utils');
// import { capitalize, truncate } from 'string-utils';

// string-utils.d.ts

// capitalize(str) -- принимает строку, возвращает строку
export function capitalize(str: string): string;

// truncate(str, maxLength, suffix) -- suffix необязательный
export function truncate(
  str: string,
  maxLength: number,
  suffix?: string   // ? -- необязательный параметр
): string;

// repeat(str, times) -- повторяет строку N раз
export function repeat(str: string, times: number): string;

// package.json
{
  "name": "string-utils",
  "version": "1.0.0",
  "main": "string-utils.js",
  "types": "string-utils.d.ts"
}

// TypeScript найдёт типы через поле "types":
// 1. import { capitalize } from 'string-utils'
// 2. TypeScript читает package.json → находит "types"
// 3. Загружает string-utils.d.ts
// 4. capitalize получает тип (str: string) => string

// string-utils-tests.ts
import { capitalize, truncate, repeat } from 'string-utils';

// Проверяем типы возврата
const cap: string = capitalize('hello');       // OK
const trunc: string = truncate('long', 3);     // OK
const rep: string = repeat('ha', 3);           // OK

// Проверяем, что ошибочный код отклоняется
// @ts-expect-error -- аргумент должен быть строкой
capitalize(123);

// @ts-expect-error -- maxLength должен быть числом
truncate('hello', 'five');

// @ts-expect-error -- результат -- строка, не число
const wrong: number = repeat('x', 3);

// string-utils.d.ts -- финальная версия

/**
 * Делает первую букву строки заглавной.
 * @param str -- исходная строка
 * @returns строка с заглавной первой буквой
 */
export function capitalize(str: string): string;

/**
 * Обрезает строку до указанной длины.
 * @param str -- исходная строка
 * @param maxLength -- максимальная длина
 * @param suffix -- суффикс при обрезке (по умолчанию '...')
 */
export function truncate(
  str: string,
  maxLength: number,
  suffix?: string
): string;

/**
 * Повторяет строку указанное количество раз.
 * @param str -- строка для повтора
 * @param times -- количество повторений
 */
export function repeat(str: string, times: number): string;
